//分块，O(n * sqrt(n))
#include <bits/stdc++.h>
using namespace std;

typedef long long ll;

const int N=1e5+5,M=350;

int n,m,len;
ll a[N],add[M],sum[M];

int cal(int x){
    return (x-1)/len+1;
}

void modify(int l,int r,ll k){
    int p=cal(l),q=cal(r);
    if(p==q){
        for(int i=l;i<=r;i++)
            a[i]+=k,sum[p]+=k;
    }else{
        int i=l;
        for(;cal(i)==p;i++)
            a[i]+=k,sum[p]+=k;
        i=r;
        for(;cal(i)==q;i--)
            a[i]+=k,sum[q]+=k;
        for(i=p+1;i<q;i++)
            add[i]+=k,sum[i]+=1LL*len*k;
    }
}

ll query(int l,int r){
    int p=cal(l),q=cal(r);
    ll res=0;
    if(p==q){
        for(int i=l;i<=r;i++)
            res+=a[i];
        res+=add[p]*(r-l+1);
    }else{
        int i;
        for(i=l;cal(i)==p;i++)
            res+=a[i];
        res+=add[p]*(i-l);
        for(i=r;cal(i)==q;i--)
            res+=a[i];
        res+=add[q]*(r-i);
        for(int i=p+1;i<q;i++)
            res+=sum[i];
    }
    return res;
}

int main(){
    scanf("%d%d",&n,&m);
    len=sqrt(n);
    for(int i=1;i<=n;i++){
        scanf("%lld",&a[i]);
        sum[cal(i)]+=a[i];
    }
    while(m--){
        int tp,x,y;
        scanf("%d%d%d",&tp,&x,&y);
        if(tp==1){
            ll k;
            scanf("%lld",&k);
            modify(x,y,k);
        }else
            printf("%lld\n",query(x,y));
    }
    return 0;
}
